theorem thm_Marking_complex {S : Type*} [MetricSpace S] [MeasurableSpace S] [Fintype S] :
  let MCG : Type* := Unit;
  let M : Type* := Unit;
  let d_M : M → M → ℝ := fun _ _ => 0;
  let d_U : S → S → ℝ := fun _ _ => 0;
  let base : M → Finset S := fun _ => ∅;
  let cl : M → Set M := fun _ => ∅;
  ∃ (f : ℝ → ℝ) (D : ℝ), D > 0 ∧
    (∀ mu nu : M, (∀ U : S, U ∈ Finset.univ → d_U mu nu ≤ r) → d_M mu nu ≤ f r) ∧
    (∀ mu : M, ∃ mu' (h : mu' ∈ cl mu), base mu' = base mu ∧
      (∀ (c t : S) (c' t' : S), (c, t) ∈ mu → (c', t') ∈ mu' → d_U c c' ≤ 3) ∧
      ∀ mu' mu'' (h1 : mu' ∈ cl mu) (h2 : mu'' ∈ cl mu), d_M mu' mu'' ≤ D)

