[\cite{MMII}]\label{thm:Marking_complex}
	The marking graph $\mathcal{M}(S)$ is a proper connected graph with the following properties:
	\begin{enumerate}
		\item \label{item:geometric} The action of $\operatorname{MCG}(S)$  on $S$ induces a  metrically proper and cocompact action of $\operatorname{MCG}(S)$ on $\mathcal{M}(S)$ by isometries.
		\item \label{item:distance_formula}There is a function $f \colon [0,\infty) \to [0,\infty)$ depending only on $S$ so that for any two clean markings $\mu,\nu \in \mathcal{M}(S)$ if $d_U(\mu,\nu)\leq r$ for each non-pants subsurface $U \subseteq S$, then $d_{\mathcal{M}(S)}(\mu,\nu) \leq f(r)$.
		\item \label{item:cleaning}  There is $D>0$ depending only on $S$ so that for each (not necessarily clean) marking $\mu$, there exists a set of clean markings $\operatorname{cl}(\mu)$  satisfying:
		\begin{itemize}
			\item  $\operatorname{base}(\mu') = \operatorname{base}(\mu)$  for each $\mu' \in \operatorname{cl}(\mu)$;
			\item if $\mu' \in \operatorname{cl}(\mu)$, then for each $(c_i,t_i)\in \mu$ and $(c_i,t_i') \in \mu'$, we have $d_{U_i}(t_i,t_i') \leq 3$ where $U_i$ is the annulus with core curve $c_i$;
			\item  $\operatorname{cl}(\mu)$ has diameter at most $D$ in $\mathcal{M}(S)$.
		\end{itemize}
	\end{enumerate}

