theorem ex_saturation {S : Type*} [MetricSpace S] (delta delta' : Finset (Set S)) :
  let U_delta := disjoint_union_non_pants_components (S \ delta);
  let lk_delta := 𝒞 U_delta;
  let Sat_delta := 𝒞0 (S \ U_delta) ∪ boundary U_delta;
  (lk_delta = lk_delta' ↔ U_delta = U_delta') ∧ Sat_delta = Sat_delta'

